---
变量更新规则:
  日期:
    format: YYYY-MM-DD
    check:
      - 时间经过24:00后，修改为下一天
      - 按照真实的日期更新
  时间:
    format: HH:mm
    check:
      - 按照剧情推进，合理地更新
  郑泽恒:
    type: |-
      {
        体力: number;
        性欲: number;
        穿着: string[];
        身体状态: {
          面部: string;
          手臂: string;
          躯干: string;
          腿部: string;
          臀部: string;
          性器官: string;
          特殊: string[];
        };
        永久性身体改造: string[];
      }
    体力:
      type: number
      range: 0~100
      check:
        - 体力消耗后缓慢恢复
        - 剧烈运动、战斗等消耗体力，单次不超过±20
    性欲:
      type: number
      range: -100~100
      check:
        - 根据色情互动调整，单次变化不超过±20
        - 暴露于色情内容提升性欲
        - 长期无接触可缓慢下降
    穿着:
      type: string[]
      check:
        - 记录角色的当前衣装打扮
        - 使用 replace 整体替换
    身体状态:
      type: |-
        {
          面部: string;
          手臂: string;
          躯干: string;
          腿部: string;
          臀部: string;
          性器官: string;
          特殊: string[];
        }
      check:
        - 按照剧情更新对应部位的描述
        - 保证状态符合实际
        - 特殊用于记录非标准身体状态，如淤青、伤痕、人体彩绘等
    永久性身体改造:
      type: string[]
      check:
        - 记录不可逆的身体改造，如纹身、穿孔等
        - 追加新条目而非覆盖
